/**
 * Precedence of an expression. For each enum value the priority is defined by its definition order.
 * 
 * Node with higher priority (lower on the list) should only be parent of nodes with lower priority.
 */
public enum Precedence {
  FUNCTION_CALL(),
  POSTFIX(),
  PREFIX(),
  TYPE_RHS(),
  MULTIPLICATIVE(),
  ADDITIVE(),
  RANGE(),
  INFIX(),
  ELVIS(),
  NAMED_CHECKS(),
  COMPARISON(),
  EQUALITY(),
  CONJUNCTION(),
  DISJUNCTION(),
  SPREAD(),
  ASSIGNMENT(),
  DEFAULT();

  public float asNumber() {
    // Order defined by definition order
    return this.ordinal();
  }

  /**
   * TODO clean that and move asNumber into int unless implemented otherwise
   */
  public static float between(Precedence a, Precedence b) {
    return (a.asNumber() + b.asNumber()) / 2;
  }

  public static boolean isApplicable(Precedence precedence) {
    // Null precedence indicate the node cannot be swapped in any case
    // If the query is about non binary operators, we cannot use precedence on binary operations
    return precedence != null;
  }

  public static Precedence notApplicable() {
    return null;
  }
}
